#include <stdio.h>

int main() {
    // Expression statements
    int a = 10, b = 20, c;
    c = a + b;  // Assignment expression
    printf("Sum: %d\n", c);

    // Compound statement (block)
    {
        int x = 5;
        printf("Inside block, x = %d\n", x);
    }

    // Null statement in loop
    int n;
    printf("Enter a number: ");
    while (scanf("%d", &n) != 1) {
        // Clear invalid input
        while (getchar() != '\n');
        printf("Invalid. Enter again: ");
    }
    printf("You entered: %d\n", n);

    return 0;
}

#include <stdio.h>

int main() {
    int a = 3, b = 4, c = 2, d = 5;

    // Expression: a + b * c / d
    // Multiplication and division have higher precedence
    // They are left-associative
    int result1 = a + b * c / d;
    // Evaluated as: a + ((b * c) / d) = 3 + (8/5) = 3 + 1 = 4
    printf("a + b * c / d = %d\n", result1);

    // Using parentheses to override precedence
    int result2 = (a + b) * c / d;
    // Evaluated as: ((a + b) * c) / d = (7*2)/5 = 14/5 = 2
    printf("(a + b) * c / d = %d\n", result2);

    // Complex expression
    int x = 10, y = 20;
    int result3 = ++x + y-- - 5 * 2;
    // x becomes 11, y returns 20 then becomes 19
    // = 11 + 20 - 10 = 21
    printf("Result: %d, x: %d, y: %d\n", result3, x, y);

    return 0;
}

#include <stdio.h>

int main() {
    int a = 25, b = 40, c = 30;

    // Simple conditional operator
    int max = (a > b) ? a : b;
    printf("Maximum of a and b: %d\n", max);

    // Nested conditional operator for three numbers
    int largest = (a > b) ? 
                  ((a > c) ? a : c) : 
                  ((b > c) ? b : c);
    printf("Largest of three: %d\n", largest);

    // Using conditional in expressions
    int num = 15;
    char* status = (num % 2 == 0) ? "Even" : "Odd";
    printf("%d is %s\n", num, status);

    // Decision making with if-else (selection statement)
    if (a > 20) {
        printf("a is greater than 20\n");
    } else if (b > 20) {
        printf("b is greater than 20\n");
    } else {
        printf("Both are 20 or less\n");
    }

    return 0;
}
